import ast
import pathlib
from dataclasses import dataclass
from typing import List


@dataclass
class ArchitecturalViolation:
    file: str
    line: int
    rule_id: str
    description: str

    def __str__(self) -> str:
        return f"{self.file}:{self.line} [{self.rule_id}] {self.description}"


def find_direct_anthropic_calls(repo_root: pathlib.Path) -> List[ArchitecturalViolation]:
    """
    FF-01: All Claude API calls must go through ClaudeClient.
    Violation: direct anthropic.messages.create anywhere outside src/claude_client.py.
    """
    violations = []
    allowed_file = repo_root / "src" / "claude_client.py"

    for py_file in repo_root.rglob("*.py"):
        if py_file == allowed_file:
            continue
        try:
            tree = ast.parse(py_file.read_text())
        except SyntaxError:
            continue

        for node in ast.walk(tree):
            if (
                isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and node.func.attr == "create"
                and isinstance(node.func.value, ast.Attribute)
                and node.func.value.attr == "messages"
            ):
                violations.append(ArchitecturalViolation(
                    file=str(py_file.relative_to(repo_root)),
                    line=node.lineno,
                    rule_id="FF-01",
                    description="Direct anthropic messages.create call outside ClaudeClient",
                ))
    return violations


def find_inline_prompt_assembly(repo_root: pathlib.Path) -> List[ArchitecturalViolation]:
    """
    FF-02: All prompt strings must be assembled in PromptBuilder.
    Violation: assignment to system_prompt or user_prompt outside src/prompt_builder.py.
    """
    violations = []
    allowed_file = repo_root / "src" / "prompt_builder.py"

    for py_file in repo_root.rglob("*.py"):
        if py_file == allowed_file:
            continue
        try:
            tree = ast.parse(py_file.read_text())
        except SyntaxError:
            continue

        for node in ast.walk(tree):
            if isinstance(node, ast.Assign):
                for target in node.targets:
                    if isinstance(target, ast.Name) and target.id in ("system_prompt", "user_prompt"):
                        violations.append(ArchitecturalViolation(
                            file=str(py_file.relative_to(repo_root)),
                            line=node.lineno,
                            rule_id="FF-02",
                            description=f"Prompt string '{target.id}' assembled outside PromptBuilder",
                        ))
    return violations


def run_structural_fitness_functions(repo_root: pathlib.Path) -> bool:
    """Returns True if all structural fitness functions pass (no violations)."""
    all_violations = (
        find_direct_anthropic_calls(repo_root)
        + find_inline_prompt_assembly(repo_root)
    )

    if all_violations:
        for v in all_violations:
            print(f"VIOLATION: {v}")
        print(f"\n{len(all_violations)} architectural violation(s). Merge blocked.")
        return False

    print("All structural fitness functions passed.")
    return True

from dataclasses import dataclass
from typing import List


@dataclass
class OperationalSample:
    latency_ms: float
    input_tokens: int
    output_tokens: int
    api_error: bool


@dataclass
class OperationalFitnessFunction:
    function_id: str
    name: str
    p95_latency_ms_max: float        # 95th-percentile latency ceiling
    cost_per_1k_inputs_usd: float
    cost_per_1k_outputs_usd: float
    max_total_cost_usd: float        # ceiling for the whole sample run
    max_error_rate: float            # e.g. 0.02 = max 2% errors

    def evaluate(self, samples: List[OperationalSample]) -> "OperationalFitnessResult":
        latencies = sorted(s.latency_ms for s in samples if not s.api_error)
        p95 = latencies[int(len(latencies) * 0.95)] if latencies else 0.0

        total_cost = sum(
            (s.input_tokens / 1000) * self.cost_per_1k_inputs_usd
            + (s.output_tokens / 1000) * self.cost_per_1k_outputs_usd
            for s in samples
        )
        error_rate = sum(1 for s in samples if s.api_error) / len(samples)

        violations = []
        if p95 > self.p95_latency_ms_max:
            violations.append(
                f"P95 latency {p95:.0f}ms exceeds limit {self.p95_latency_ms_max:.0f}ms"
            )
        if total_cost > self.max_total_cost_usd:
            violations.append(
                f"Total cost ${total_cost:.4f} exceeds limit ${self.max_total_cost_usd:.4f}"
            )
        if error_rate > self.max_error_rate:
            violations.append(
                f"Error rate {error_rate:.1%} exceeds limit {self.max_error_rate:.1%}"
            )

        return OperationalFitnessResult(
            function_id=self.function_id,
            p95_latency_ms=p95,
            total_cost_usd=total_cost,
            error_rate=error_rate,
            violations=violations,
        )


@dataclass
class OperationalFitnessResult:
    function_id: str
    p95_latency_ms: float
    total_cost_usd: float
    error_rate: float
    violations: List[str]

    def passed(self) -> bool:
        return len(self.violations) == 0

    def summary(self) -> str:
        status = "PASS" if self.passed() else "FAIL"
        lines = [
            f"[{self.function_id}] {status}",
            f"  P95 latency: {self.p95_latency_ms:.0f}ms",
            f"  Total cost:  ${self.total_cost_usd:.4f}",
            f"  Error rate:  {self.error_rate:.1%}",
        ]
        for v in self.violations:
            lines.append(f"  VIOLATION: {v}")
        return "\n".join(lines)

from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, List, Optional
import datetime


class FFCategory(Enum):
    STRUCTURAL   = "structural"
    BEHAVIOURAL  = "behavioural"
    OPERATIONAL  = "operational"


class FFState(Enum):
    ACTIVE     = "active"
    SUPPRESSED = "suppressed"   # Temporarily disabled; must have expiry date
    RETIRED    = "retired"      # Permanently removed; kept for audit history


@dataclass
class FitnessFunctionEntry:
    ff_id: str
    name: str
    category: FFCategory
    invariant: str
    adr_id: Optional[str]                # ADR that introduced this FF
    owner: str
    blocking: bool
    state: FFState = FFState.ACTIVE
    suppressed_until: Optional[str] = None   # ISO-8601 date
    suppression_reason: Optional[str] = None
    retired_date: Optional[str] = None
    retired_reason: Optional[str] = None

    def is_currently_active(self) -> bool:
        if self.state == FFState.RETIRED:
            return False
        if self.state == FFState.SUPPRESSED and self.suppressed_until:
            return datetime.date.today() > datetime.date.fromisoformat(self.suppressed_until)
        return self.state == FFState.ACTIVE

    def registry_row(self) -> str:
        state_label = self.state.value.upper()
        if self.state == FFState.SUPPRESSED and self.suppressed_until:
            state_label += f" until {self.suppressed_until}"
        return (
            f"{self.ff_id:<8} | {self.category.value:<12} | "
            f"{'BLOCK' if self.blocking else 'WARN':<5} | "
            f"{state_label:<22} | {self.name}"
        )


class FitnessFunctionRegistry:
    def __init__(self) -> None:
        self._entries: Dict[str, FitnessFunctionEntry] = {}

    def register(self, entry: FitnessFunctionEntry) -> None:
        self._entries[entry.ff_id] = entry

    def active_blocking(self) -> List[FitnessFunctionEntry]:
        return [e for e in self._entries.values() if e.is_currently_active() and e.blocking]

    def suppressed_entries(self) -> List[FitnessFunctionEntry]:
        return [e for e in self._entries.values() if e.state == FFState.SUPPRESSED]

    def coverage_by_category(self) -> Dict[str, int]:
        counts: Dict[str, int] = {cat.value: 0 for cat in FFCategory}
        for e in self._entries.values():
            if e.is_currently_active():
                counts[e.category.value] += 1
        return counts

    def audit_report(self) -> str:
        lines = [
            "Fitness Function Registry Audit",
            "=" * 50,
            f"{'FF-ID':<8} | {'Category':<12} | {'Gate':<5} | {'State':<22} | Name",
            "-" * 75,
        ]
        for e in sorted(self._entries.values(), key=lambda x: x.ff_id):
            lines.append(e.registry_row())
        coverage = self.coverage_by_category()
        lines += [
            "",
            "Coverage by category:",
            *[f"  {cat}: {count} active" for cat, count in coverage.items()],
            f"Suppressed: {len(self.suppressed_entries())} (require review)",
        ]
        return "\n".join(lines)
